"use client";

/* Bridge surface — /bridge/[dept]/[surface].
   Each surface is lazily imported, so only the clicked surface's JS loads
   ("load on click"). The URL carries dept + surface (and ?id=… for the
   entity later), making every surface a unique, deep-linkable page. */

import dynamic from "next/dynamic";
import { useParams } from "next/navigation";
import type { ComponentType } from "react";

const SURFACES: Record<string, ComponentType> = {
  // ── Operations (built) ──
  "new-item": dynamic(() => import("@/features/bridge/components/BridgeNewItem").then((m) => m.BridgeNewItem)),
  reorder: dynamic(() => import("@/features/bridge/components/BridgeReorder").then((m) => m.BridgeReorder)),
  liquidate: dynamic(() => import("@/features/bridge/components/BridgeLiquidate").then((m) => m.BridgeLiquidate)),
  return: dynamic(() => import("@/features/bridge/components/BridgeReturn").then((m) => m.BridgeReturn)),
  "add-supplier": dynamic(() => import("@/features/bridge/components/BridgeAddSupplier").then((m) => m.BridgeAddSupplier)),
  "add-category": dynamic(() => import("@/features/bridge/components/BridgeAddCategory").then((m) => m.BridgeAddCategory)),
  receive: dynamic(() => import("@/features/bridge/components/BridgeReceive").then((m) => m.BridgeReceive)),
  // ── Finance (built) ──
  classify: dynamic(() => import("@/features/bridge/components/BridgeClassify").then((m) => m.BridgeClassify)),
  "approve-payment": dynamic(() => import("@/features/bridge/components/BridgeApprovePayment").then((m) => m.BridgeApprovePayment)),
  "log-entry": dynamic(() => import("@/features/bridge/components/BridgeLogEntry").then((m) => m.BridgeLogEntry)),
  "recurring-cost": dynamic(() => import("@/features/bridge/components/BridgeRecurringCost").then((m) => m.BridgeRecurringCost)),
  reconcile: dynamic(() => import("@/features/bridge/components/BridgeReconcile").then((m) => m.BridgeReconcile)),
  "close-month": dynamic(() => import("@/features/bridge/components/BridgeCloseMonth").then((m) => m.BridgeCloseMonth)),
};

function titleize(slug: string) {
  return slug.split("-").map((w) => w.charAt(0).toUpperCase() + w.slice(1)).join(" ");
}

function SurfaceStub({ slug }: { slug: string }) {
  return (
    <div className="bridge-content">
      <div className="bridge-page-head">
        <div className="bridge-page-head-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <circle cx="12" cy="12" r="9" />
            <path d="M12 7v6M12 17h.01" />
          </svg>
        </div>
        <div>
          <div className="bridge-page-head-title">{titleize(slug)}</div>
          <div className="bridge-page-head-sub">This surface isn&rsquo;t built yet — check back soon.</div>
        </div>
      </div>
      <div className="bridge-stub">
        <p>Coming soon. For now, head back to the Bridge home.</p>
      </div>
    </div>
  );
}

export default function BridgeSurfacePage() {
  const { surface } = useParams();
  const slug = String(surface);
  const Surface = SURFACES[slug];
  return Surface ? <Surface /> : <SurfaceStub slug={slug} />;
}
